if (! function_exists('html_to_markdown')) {
    function html_to_markdown($html, $strip_nav = null, $escape_markdown = null, $max_output_length = null, $timeout = null)
    {
        $html = $html ?? '';
        $strip_nav = $strip_nav ?? true;
        $escape_markdown = $escape_markdown ?? true;
        $max_output_length = $max_output_length ?? 100000;
        $max_output_length = max(0, min(500000, $max_output_length));
        $timeout = $timeout ?? 5;

        if (empty($html)) {
            return ['error' => 'No HTML content provided.'];
        }

        $start = microtime(true);

        libxml_use_internal_errors(true);
        $dom = new DOMDocument();
        // Wrap in a UTF-8 declaration to avoid encoding issues
        $dom->loadHTML('<?xml encoding="UTF-8">' . $html);
        libxml_clear_errors();

        $xpath = new DOMXPath($dom);

        // Remove unwanted elements
        if ($strip_nav) {
            $removeTags = ['//nav', '//aside', '//footer', '//script', '//style', '//noscript', '//form', '//iframe', '//svg', '//header'];
            foreach ($removeTags as $expr) {
                $nodes = $xpath->query($expr);
                foreach ($nodes as $node) {
                    if ($node->parentNode) {
                        $node->parentNode->removeChild($node);
                    }
                }
            }
        }

        // Escape Markdown special characters
        $escapeFn = function($text) use ($escape_markdown) {
            if (!$escape_markdown || $text === '') return $text;
            $result = '';
            $len = strlen($text);
            for ($i = 0; $i < $len; $i++) {
                $ch = $text[$i];
                if (strpos('\\`*_{}[]()#+-.!|>~', $ch) !== false) {
                    $result .= '\\' . $ch;
                } else {
                    $result .= $ch;
                }
            }
            return $result;
        };

        // Get the text content of children recursively, converting inline elements
        $inlineContent = function($node) use (&$inlineContent, $escapeFn) {
            $result = '';
            foreach ($node->childNodes as $child) {
                if ($child instanceof DOMText) {
                    $result .= $escapeFn($child->wholeText);
                } elseif ($child instanceof DOMElement) {
                    $tag = strtolower($child->tagName);
                    $inner = $inlineContent($child);
                    
                    if ($tag === 'a') {
                        $href = $child->getAttribute('href');
                        if ($href !== '' && strpos($href, 'javascript:') !== 0) {
                            $result .= '[' . $inner . '](' . $href . ')';
                        } else {
                            $result .= $inner;
                        }
                    } elseif ($tag === 'img') {
                        $src = $child->getAttribute('src');
                        $alt = $child->getAttribute('alt');
                        $result .= '![' . $escapeFn($alt) . '](' . $src . ')';
                    } elseif (in_array($tag, ['strong', 'b'], true)) {
                        $result .= '**' . $inner . '**';
                    } elseif (in_array($tag, ['em', 'i'], true)) {
                        $result .= '*' . $inner . '*';
                    } elseif ($tag === 'code') {
                        $result .= '`' . $inner . '`';
                    } elseif ($tag === 'br') {
                        $result .= "\n";
                    } elseif ($tag === 'span') {
                        $result .= $inner;
                    } elseif (in_array($tag, ['del', 's'], true)) {
                        $result .= '~~' . $inner . '~~';
                    } else {
                        $result .= $inner;
                    }
                }
            }
            return $result;
        };

        // Block-level converter
        $convertBlocks = function($node, $depth = 0) use (&$convertBlocks, $xpath, $inlineContent, $escapeFn) {
            $md = '';
            $indent = str_repeat('  ', $depth);
            
            foreach ($node->childNodes as $child) {
                if (!($child instanceof DOMElement)) continue;
                
                $tag = strtolower($child->tagName);
                
                if (in_array($tag, ['h1', 'h2', 'h3', 'h4', 'h5', 'h6'], true)) {
                    $level = (int)substr($tag, 1);
                    $prefix = str_repeat('#', $level);
                    $text = trim($inlineContent($child));
                    if ($text !== '') {
                        $md .= "\n" . $prefix . ' ' . $text . "\n\n";
                    }
                } elseif ($tag === 'p') {
                    $text = trim($inlineContent($child));
                    if ($text !== '') {
                        $md .= $text . "\n\n";
                    }
                } elseif ($tag === 'hr') {
                    $md .= "\n---\n\n";
                } elseif (in_array($tag, ['ul', 'ol'], true)) {
                    $is_ol = ($tag === 'ol');
                    $counter = 1;
                    foreach ($child->childNodes as $item) {
                        if ($item instanceof DOMElement && strtolower($item->tagName) === 'li') {
                            $bullet = $is_ol ? $counter . '.' : '-';
                            $text = trim($inlineContent($item));
                            if ($text !== '') {
                                $md .= $indent . $bullet . ' ' . $text . "\n";
                            }
                            // Nested lists
                            foreach ($item->childNodes as $sub) {
                                if ($sub instanceof DOMElement && in_array(strtolower($sub->tagName), ['ul', 'ol'], true)) {
                                    $md .= $convertBlocks($sub, $depth + 1);
                                }
                            }
                            $counter++;
                        }
                    }
                    $md .= "\n";
                } elseif ($tag === 'blockquote') {
                    $inner = $convertBlocks($child, 0);
                    $lines = explode("\n", trim($inner));
                    foreach ($lines as $line) {
                        if (trim($line) !== '') {
                            $md .= '> ' . $line . "\n";
                        }
                    }
                    $md .= "\n";
                } elseif ($tag === 'pre') {
                    $code = '';
                    $lang = '';
                    foreach ($child->childNodes as $sub) {
                        if ($sub instanceof DOMElement && strtolower($sub->tagName) === 'code') {
                            $code = $sub->textContent;
                            $cls = $sub->getAttribute('class');
                            if (preg_match('/language-(\w+)/', $cls, $m)) {
                                $lang = $m[1];
                            }
                        }
                    }
                    if ($code === '') {
                        $code = $child->textContent;
                    }
                    $code = trim($code);
                    if ($code !== '') {
                        $md .= "\n```" . $lang . "\n" . $code . "\n```\n\n";
                    }
                } elseif ($tag === 'table') {
                    $rows_output = [];
                    $headers = [];
                    $rows_data = [];
                    $maxCols = 0;
                    
                    // Find all rows
                    $trs = $xpath->query('.//tr', $child);
                    foreach ($trs as $tr) {
                        $cells = [];
                        $isHeader = false;
                        $ths = $xpath->query('.//th', $tr);
                        $tds = $xpath->query('.//td', $tr);
                        foreach ($ths as $th) { $cells[] = trim($inlineContent($th)); $isHeader = true; }
                        foreach ($tds as $td) { $cells[] = trim($inlineContent($td)); }
                        if (!empty($cells)) {
                            if ($isHeader && empty($headers)) {
                                $headers = $cells;
                            } else {
                                $rows_data[] = $cells;
                            }
                            if (count($cells) > $maxCols) $maxCols = count($cells);
                        }
                    }
                    
                    if ($maxCols > 0) {
                        if (empty($headers)) {
                            $headers = array_fill(0, $maxCols, '');
                        }
                        $md .= "\n";
                        $md .= '| ' . implode(' | ', array_pad($headers, $maxCols, '')) . " |\n";
                        $md .= '| ' . implode(' | ', array_fill(0, $maxCols, '---')) . " |\n";
                        foreach ($rows_data as $row) {
                            $md .= '| ' . implode(' | ', array_pad($row, $maxCols, '')) . " |\n";
